WITH row_rank_1 AS (
    SELECT rr.COMPANY_PK, rr.COMPANY_CD, rr.LOAD_DATE, rr.RECORD_SOURCE,
           ROW_NUMBER() OVER(
               PARTITION BY rr.COMPANY_PK
               ORDER BY rr.LOAD_DATE
           ) AS row_number
    FROM S45969_DBT_DB.S45969_DBT_AH_SCHEMA.v_stg_company AS rr
    WHERE rr.COMPANY_PK IS NOT NULL
    QUALIFY row_number = 1
),

records_to_insert AS (
    SELECT a.COMPANY_PK, a.COMPANY_CD, a.LOAD_DATE, a.RECORD_SOURCE
    FROM row_rank_1 AS a
    LEFT JOIN S45969_DBT_DB.S45969_DBT_AH_SCHEMA.hub_company AS d
    ON a.COMPANY_PK = d.COMPANY_PK
    WHERE d.COMPANY_PK IS NULL
)

SELECT * FROM records_to_insert